mapper.select:
/* #{seq_counsel}: Java에서 넘겨준 파라미터 값(글 번호)이 들어갈 자리입니다.
  내부적으로 PreparedStatement(?)를 사용하여 값에 포함된 특수기호를 안전하게 처리하므로 SQL 인젝션 해킹을 막아줍니다.
  [변경 시] ${seq_counsel} (달러 기호)로 바꾸면, 값을 문자열 그대로 쿼리에 이어 붙이기 때문에 해킹 공격에 뚫릴 위험이 매우 높아집니다.
*/
SELECT * FROM COUNSEL_INFO WHERE seq_counsel = #{seq_counsel}

mapper.insert:

    /* MariaDB의 시퀀스에서 다음 번호를 뽑아옵니다. (Oracle의 시퀀스.NEXTVAL 과 동일한 역할) */
    SELECT NEXTVAL(seq_counsel)

/* 위에서 뽑아서 셋팅해준 #{seq_counsel}을 포함하여 모든 데이터를 DB에 밀어 넣습니다. */
INSERT INTO COUNSEL_INFO (seq_counsel, counsel_title, counsel_content, counsel_writer)
VALUES (#{seq_counsel}, #{counsel_title}, #{counsel_content}, #{counsel_writer})

mapper.update:
UPDATE COUNSEL_INFO
SET counsel_title = #{counsel_title},
    counsel_content = #{counsel_content}
/* WHERE 절이 매우 중요합니다! 특정 글 번호만 수정하도록 조건을 겁니다.
  [삭제 시] WHERE 절을 실수로 지우면, 게시판에 있는 10만 개의 게시글 제목과 내용이 방금 수정한 글로 다 똑같이 바뀌는 대형 사고가 납니다!
*/
WHERE seq_counsel = #{seq_counsel}
